import React from "react";
import { useEffect } from "react";
import { useDispatch } from "react-redux";
import { Link as LinkRouter } from "react-router-dom" 
import citiesActions from "../redux/citiesActions";
import "../styles/cardsCities.css"

export default function CardsCities({ cardFilter }) {

    const dispatch = useDispatch()

    useEffect(()=>{
        dispatch(citiesActions.filterCities())
    },[])
    return(
        <div className="card-container">
        {cardFilter.map(city => (
            <div className="card" key={city._id}>
                <div className="image">
                <img className="image-card" src= {city.image} alt="cities" />
                </div>
                <div>
                    <h2>{city.cityname}</h2>
                    <h3>{city.country}</h3>
                    <LinkRouter to={`/cities/${city._id}`}>
                        See more
                    </LinkRouter>
                </div>
            </div>
        ))}
        </div>
    );
}
